/* ═══════════════════════════════════════════════
   CRACK OVERLAY
═══════════════════════════════════════════════ */
export const CrackOverlay = ({ stage, size = 44 }: { stage: number; size?: number }) => {
  if (stage === 0) return null;
  const s = size / 48;
  const c1 = "M14,2 L10,8 L16,12 L8,22 L14,26";
  const c2 = c1 + " M32,4 L28,10 L34,14 L28,24 L32,30";
  const c3 = c2 + " M4,28 L10,32 L6,38 L12,42 M36,28 L40,34 L36,40";
  const d = stage === 1 ? c1 : stage === 2 ? c2 : c3;
  return (
    <svg width={size} height={size} viewBox="0 0 48 48" style={{ position: "absolute", inset: 0, pointerEvents: "none" }}>
      <path d={d} fill="none" stroke="rgba(0,0,0,0.45)" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"/>
      <path d={d} fill="none" stroke="rgba(0,0,0,0.92)" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
      <path d={d} fill="none" stroke="rgba(255,255,255,0.12)" strokeWidth="0.7" strokeLinecap="round" strokeLinejoin="round" transform="translate(0.8,0.8)"/>
    </svg>
  );
};

/* ═══════════════════════════════════════════════
   BLOCK BY TYPE
═══════════════════════════════════════════════ */
export const BlockByType = ({ type, crackStage = 0, size = 44 }: { type: number; crackStage?: number; size?: number }) => {
  const blocks = [SandBlock, LimestoneBlock, CopperOreBlock, SilverOreBlock, GoldOreBlock, RubyBlock];
  const Block = blocks[type % 6];
  return (
    <div style={{ position: "relative", width: size, height: size }}>
      <Block size={size} />
      <CrackOverlay stage={crackStage} size={size} />
    </div>
  );
};

