/* ═══════════════════════════════════════════════
   TOOL BY TYPE (0=Petard, 1=Dynamite, 2=GoldPickaxe, 3=Drill)
═══════════════════════════════════════════════ */
export const ToolByType = ({ type, size = 44 }: { type: number; size?: number }) => {
  const glows = ["#FF4422", "#FF2200", "#FFD700", "#AAAACC"];
  const tools = [
    <PetardTool size={size} />,
    <DynamiteTool size={size} />,
    <GoldPickaxeTool size={size} />,
    <DrillTool size={size} />,
  ];
  return (
    <div style={{ filter: type !== 2 ? `drop-shadow(0 0 6px ${glows[type]})` : undefined }}>
      {tools[type % 4]}
    </div>
  );
};

